/* ---------- analytics engine (runs per plant) ---------- */
function analyze(items,gone,month){
  const left=Math.max(month-gone,1);
  const IT=items.map(r=>({...r,prS:r.dp.reduce((a,b)=>a+b,0)}));
  const T=IT.reduce((a,r)=>({sch:a.sch+r.sch,inv:a.inv+r.inv,bal:a.bal+r.bal,prod:a.prod+r.pr,
    rej:a.rej+r.rej,stk:a.stk+r.stk,ih:a.ih+r.ihs,vn:a.vn+r.vns,qi:a.qi+r.qis,
    ihU:a.ihU+r.ihU,qiR:a.qiR+r.qiR,vnR:a.vnR+r.vnR,res:a.res+r.res,resKg:a.resKg+r.res*r.w}),
    {sch:0,inv:0,bal:0,prod:0,rej:0,stk:0,ih:0,vn:0,qi:0,ihU:0,qiR:0,vnR:0,res:0,resKg:0});
  const DAILY=Array.from({length:gone},(_,i)=>({day:String(i+1).padStart(2,"0"),
    Production:IT.reduce((a,r)=>a+(r.dp[i]||0),0),Dispatch:IT.reduce((a,r)=>a+(r.dd[i]||0),0)}));
  const lines=[...new Set(IT.map(r=>r.ln))].sort((a,b)=>
    IT.filter(r=>r.ln===b).reduce((x,r)=>x+r.sch,0)-IT.filter(r=>r.ln===a).reduce((x,r)=>x+r.sch,0));
  const LS=lines.map(ln=>{
    const g=IT.filter(r=>r.ln===ln);
    const daily=Array.from({length:gone},(_,i)=>g.reduce((a,r)=>a+(r.dp[i]||0),0));
    const active=daily.filter(d=>d>0);
    const avg=active.length?active.reduce((a,b)=>a+b,0)/active.length:0;
    const res=g.reduce((a,r)=>a+r.res,0);
    return{ln,n:g.length,sch:g.reduce((a,r)=>a+r.sch,0),inv:g.reduce((a,r)=>a+r.inv,0),
      bal:g.reduce((a,r)=>a+r.bal,0),res,req:res/left,avg,daysRun:active.length,
      load:avg>0?100*(res/left)/avg:(res>0?Infinity:0)};});
  const RS=RCA_ORDER.map(k=>{const g=IT.filter(r=>r.rca===k);
    return{k,n:g.length,qty:k==="QI HOLD"?g.reduce((a,r)=>a+r.qiR,0):
      k==="VENDOR PULL"?g.reduce((a,r)=>a+r.vnR,0):
      k==="DISPATCH EXEC"?g.reduce((a,r)=>a+r.bal,0):g.reduce((a,r)=>a+r.res,0)};});
  const P=(()=>{const rs=IT.filter(r=>r.res>0).sort((a,b)=>b.res-a.res);
    const tot=rs.reduce((a,r)=>a+r.res,0)||1;let cum=0;
    return rs.map((r,i)=>{cum+=r.res;return{rank:i+1,mc:r.mc,res:r.res,cum:100*cum/tot,ln:r.ln,d:r.d};});})();
  const N80=Math.max(P.findIndex(p=>p.cum>=80)+1,0);
  const REJ=[...IT].filter(r=>r.rej>0).sort((a,b)=>b.rej-a.rej);
  const demo=LS.reduce((a,l)=>a+l.avg,0);
  return{IT,T,DAILY,LS,RS,P,N80,REJ,lines,demo,gone,month,left,
    dispatchPct:pct(T.inv,T.sch),rejPct:pct(T.rej,T.prod+T.rej),
    feas:T.res>0?100*demo/(T.res/left):Infinity,
    bestDay:Math.max(...DAILY.map(d=>d.Dispatch),0),reqRate:T.bal/left};
}
/* ---------- daily upload: in-browser .xls parsing (mirrors the build pipeline) ---------- */
const NORM=s=>String(s==null?"":s).toLowerCase().replace(/[^a-z0-9]/g,"");
function detectPlant(name){const n=name.toUpperCase();
  if(n.indexOf("PEFCO")>=0)return"PEFCO";
  if(n.indexOf("CHK")>=0||n.indexOf("CHAKAN")>=0)return"CHAKAN";
  if(n.indexOf("HALOL")>=0)return"HALOL"; return null;}

async function parsePlantFile(file){
  const buf=await file.arrayBuffer();
  const wb=XLSX.read(buf,{type:"array"});
  const ws=wb.Sheets[wb.SheetNames[0]];
  const rows=XLSX.utils.sheet_to_json(ws,{header:1,raw:true,defval:null});
  if(rows.length<6)throw new Error("file too short to be a planning report");
  /* report period: title text first, filename DD_MM_YY second */
  let gone=null,month=null,label=null;
  const head=rows.slice(0,4).flat().filter(x=>typeof x==="string").join(" ");
  let m=head.match(/FROM\s*(\d{2})\.(\d{2})\.(\d{4})\s*TO\s*(\d{2})\.(\d{2})\.(\d{4})/i);
  if(m){gone=parseInt(m[4],10);month=new Date(parseInt(m[6],10),parseInt(m[5],10),0).getDate();
    label=m[1]+"."+m[2]+"."+m[3]+" \u2013 "+m[4]+"."+m[5]+"."+m[6];}
  if(gone==null){const f=file.name.match(/(\d{2})[_-](\d{2})[_-](\d{2,4})/);
    if(f){gone=parseInt(f[1],10);const y=f[3].length===2?2000+parseInt(f[3],10):parseInt(f[3],10);
      month=new Date(y,parseInt(f[2],10),0).getDate();label="day "+gone+" \u00b7 "+f[2]+"/"+y;}}
  if(gone==null){gone=10;month=31;label="period unknown \u2014 assumed day 10 of 31";}
  gone=Math.min(Math.max(gone,1),31); if(!month||month<28||month>31)month=31;
  /* header row (4th row) \u2192 normalized column index */
  const hdr=rows[3]||[]; const ix={};
  hdr.forEach((h,i)=>{const n=NORM(h); if(n&&!(n in ix))ix[n]=i;});
  const need=["productionline","oldmaterialcode","totschqty","invqty","baldelqty","inhousestock","vendorstock","qualityinspection","totalstock","prodcumqty","rejqty","stktobemnt","tobeprod"];
  const missing=need.filter(k=>!(k in ix));
  if(missing.length)throw new Error("missing expected columns ("+missing.slice(0,3).join(", ")+"\u2026) \u2014 is this the plant planning report?");
  const num=v=>{const n=typeof v==="number"?v:parseFloat(v);return isFinite(n)?n:0;};
  const gv=(row,k)=>(k in ix)?row[ix[k]]:null;
  const items=[];
  for(let r=4;r<rows.length;r++){
    const row=rows[r]||[]; const pl=gv(row,"productionline");
    if(typeof pl!=="string"||!pl.trim())continue;
    const sch=Math.round(num(gv(row,"totschqty")));
    const bal=Math.round(num(gv(row,"baldelqty")));
    const ihs=Math.round(num(gv(row,"inhousestock"))),vns=Math.round(num(gv(row,"vendorstock"))),qis=Math.round(num(gv(row,"qualityinspection")));
    const dd=[],dp=[]; let prS=0;
    for(let d=1;d<=31;d++){const pv=Math.round(num(gv(row,"pr"+d)));prS+=pv;
      if(d<=gone){dd.push(Math.round(num(gv(row,"day"+d))));dp.push(pv);}}
    let ihU=0,qiR=0,vnR=0,res=0,rca=null;
    if(bal>0){ihU=Math.min(ihs,bal);let rem=bal-ihU;qiR=Math.min(qis,rem);rem-=qiR;
      vnR=Math.min(vns,rem);rem-=vnR;res=rem;
      rca=res>0?(prS===0?"NOT LOADED":"UNDER-RUN"):(vnR>0?"VENDOR PULL":(qiR>0?"QI HOLD":"DISPATCH EXEC"));}
    const uw=num(gv(row,"totschqtyunitwt"));
    items.push({ln:pl.trim(),mc:String(gv(row,"oldmaterialcode")==null?"":gv(row,"oldmaterialcode")).trim(),
      g:String(gv(row,"matgrp2")==null?"":gv(row,"matgrp2")).trim(),
      d:String(gv(row,"productdiscription")==null?"":gv(row,"productdiscription")).trim().slice(0,60),
      sch,inv:Math.round(num(gv(row,"invqty"))),bal,ihs,vns,qis,
      stk:Math.round(num(gv(row,"totalstock"))),pr:Math.round(num(gv(row,"prodcumqty"))),
      rej:Math.round(num(gv(row,"rejqty"))),ms:Math.round(num(gv(row,"stktobemnt"))),
      tb:Math.round(num(gv(row,"tobeprod"))),w:sch>0?Math.round(uw/sch*1000)/1000:0,
      ihU,qiR,vnR,res,rca,dd,dp});
  }
  if(!items.length)throw new Error("no data rows found under the header");
  return {items,gone,month,label};
}

/* ---------- atoms ---------- */
const Lb=({children,style})=><div style={{fontFamily:C.sans,fontSize:10,letterSpacing:"0.13em",textTransform:"uppercase",color:C.slate,fontWeight:600,...style}}>{children}</div>;
const Nm=({v,color=C.ink,size=22,suffix})=><div style={{fontFamily:C.mono,fontSize:size,fontWeight:600,color,lineHeight:1.12,letterSpacing:"-0.01em",fontVariantNumeric:"tabular-nums"}}>{typeof v==="number"?fmt(v):v}{suffix&&<span style={{fontSize:size*0.55,color:C.slate,fontWeight:500}}> {suffix}</span>}</div>;
const Pn=({children,style,className})=><div className={"eiCard"+(className?" "+className:"")} style={{background:C.panel,border:`1px solid ${C.hair}`,borderRadius:C.radius,padding:18,boxShadow:C.shadow,...style}}>{children}</div>;
const Tag=({rca,small})=>{const m=RCA_META[rca];if(!m)return null;
  return <span style={{fontFamily:C.mono,fontSize:small?8.5:9.5,fontWeight:700,color:m.c,background:m.s,border:`1px solid ${m.c}30`,borderRadius:999,padding:"2px 9px",whiteSpace:"nowrap",letterSpacing:"0.02em"}}>{rca}</span>;};
const Spark=({dp,dd,w=110,h=26})=>{const mx=Math.max(...dp,...dd,1),bw=w/Math.max(dp.length,1);
  return(<svg width={w} height={h} style={{display:"block"}}>
    {dp.map((v,i)=><rect key={"p"+i} x={i*bw+1} y={h-(v/mx)*h} width={bw*0.42} height={(v/mx)*h||0.5} fill={C.navy} opacity={v?1:0.15}/>)}
    {dd.map((v,i)=><rect key={"d"+i} x={i*bw+1+bw*0.46} y={h-(v/mx)*h} width={bw*0.42} height={(v/mx)*h||0.5} fill={C.red} opacity={v?0.9:0.15}/>)}
  </svg>);};
const Waterfall=({T})=>{
  const segs=[{k:"Ship from in-house stock",v:T.ihU,c:C.green},{k:"Unlock: clear QI holds",v:T.qiR,c:C.violet},
    {k:"Unlock: pull vendor stock",v:T.vnR,c:C.amber},{k:"Must still produce",v:T.res,c:C.red}];
  return(<div>
    <div style={{display:"flex",height:34,borderRadius:5,overflow:"hidden",border:`1px solid ${C.hair}`}}>
      {segs.map(s=>s.v>0&&<div key={s.k} title={s.k} style={{width:`${100*s.v/T.bal}%`,background:s.c,display:"flex",alignItems:"center",justifyContent:"center"}}>
        {pct(s.v,T.bal)>=6&&<span style={{fontFamily:C.mono,fontSize:10,color:"#fff",fontWeight:700}}>{pct(s.v,T.bal).toFixed(0)}%</span>}</div>)}
    </div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(145px,1fr))",gap:8,marginTop:10}}>
      {segs.map(s=><div key={s.k} style={{borderLeft:`3px solid ${s.c}`,paddingLeft:8}}>
        <div style={{fontFamily:C.sans,fontSize:10.5,color:C.slate}}>{s.k}</div>
        <div style={{fontFamily:C.mono,fontSize:15,fontWeight:700,color:C.ink}}>{fmt(s.v)} <span style={{fontSize:10,color:C.slate}}>pcs</span></div>
      </div>)}
    </div>
  </div>);};

